public static long[] solve(long c, long[][] connections, long[][] queries) {
    // Implement DSU
    int n = (int)c;
    DSU dsu = new DSU(n);
    for (long[] conn : connections) {
        long u = conn[0];
        long v = conn[1];
        dsu.union((int)u, (int)v);
    }

    // Build componentMap
    Map<Integer, List<Integer>> componentMap = new HashMap<>();
    for (int i = 1; i <= n; i++) {
        int root = dsu.find(i);
        componentMap.computeIfAbsent(root, k -> new ArrayList<>()).add(i);
    }

    // Build componentSets
    Map<Integer, TreeSet<Integer>> componentSets = new HashMap<>();
    for (Map.Entry<Integer, List<Integer>> entry : componentMap.entrySet()) {
        int root = entry.getKey();
        List<Integer> stations = entry.getValue();
        TreeSet<Integer> set = new TreeSet<>();
        for (int station : stations) {
            set.add(station);
        }
        componentSets.put(root, set);
    }

    // Online array
    boolean[] online = new boolean[n + 1];
    for (int i = 1; i <= n; i++) {
        online[i] = true;
    }

    // Process queries
    List<Long> result = new ArrayList<>();
    for (long[] query : queries) {
        int type = (int) query[0];
        int x = (int) query[1];
        if (type == 1) {
            if (online[x]) {
