            int root = dsu.find(x);
            TreeSet<Integer> set = componentSets.get(root);
            if (set != null) {
                set.remove(x);
            }
        }
    }

    // Convert to long array
    long[] res = new long[result.size()];
    for (int i = 0; i < res.length; i++) {
        res[i] = result.get(i);
    }
    return res;
}

