import java.util.*;

public class Solution {
    public static long[] solve(long c, long[][] connections, long[][] queries) {
        int size = (int) c;
        int[] parent = new int[size + 1];
        int[] rank = new int[size + 1];

        for (int i = 1; i <= size; i++) {
            parent[i] = i;
            rank[i] = 1;
        }

        // Helper function for find with path compression
        // This is implemented inline in the code
