            long u = conn[0];
            long v = conn[1];
            int uInt = (int) u;
            int vInt = (int) v;
            int rootU = find(parent, uInt);
            int rootV = find(parent, vInt);
            if (rootU != rootV) {
                if (rank[rootU] < rank[rootV]) {
                    parent[rootU] = rootV;
                } else {
                    parent[rootV] = rootU;
                    if (rank[rootU] == rank[rootV]) {
                        rank[rootU]++;
                    }
                }
            }
        }

        // Group stations into components
        Map<Integer, TreeSet<Integer>> componentMap = new HashMap<>();
        for (int i = 1; i <= size; i++) {
            int root = find(parent, i);
            if (!componentMap.containsKey(root)) {
                componentMap.put(root, new TreeSet<>());
            }
            componentMap.get(root).add(i);
        }

        // Initialize online array
