                    TreeSet<Integer> set = componentMap.get(root);
                    if (set.isEmpty()) {
                        result.add(-1L);
                    } else {
                        int min = set.first();
                        result.add((long) min);
                    }
                }
            } else {
                online[x] = false;
                int root = find(parent, x);
                TreeSet<Integer> set = componentMap.get(root);
                set.remove(x);
            }
        }

        long[] res = new long[result.size()];
        for (int i = 0; i < res.length; i++) {
            res[i] = result.get(i);
        }
        return res;
